     1→import { Logger } from '@nestjs/common';
     2→import { Command, CommandRunner, Option } from 'nest-commander';
     3→
     4→import { RedshiftTrendingItemsService } from '@modules/db/redshift/trending-items/redshift-trending-items.service';
     5→
     6→import { CronJobExecution } from '@decorators/cron-job-execution.decorator';
     7→
     8→interface PopulateTrendingItemsOptions {
     9→	startYear?: number;
    10→	endYear?: number;
    11→	months?: string;
    12→	lastWeek?: boolean;
    13→}
    14→
    15→@Command({
    16→	name: 'populate-trending-items',
    17→	description: 'Fetch order data from Redshift and populate product_annual_sales table',
    18→})
    19→export class PopulateTrendingItemsCommand extends CommandRunner {
    20→	private readonly logger = new Logger(PopulateTrendingItemsCommand.name);
    21→	private isShuttingDown = false;
    22→	private currentOperation: Promise<void> | null = null;
    23→
    24→	constructor(
    25→		private readonly redshiftTrendingItemsService: RedshiftTrendingItemsService,
    26→	) {
    27→		super();
    28→		this.setupGracefulShutdown();
    29→	}
    30→
    31→	@CronJobExecution({ jobName: 'populate-trending-items' })
    32→	async run(
    33→		_passedParams: string[],
    34→		options: PopulateTrendingItemsOptions,
    35→	): Promise<void> {
    36→		if (this.isShuttingDown) {
    37→			this.logger.warn('Command cancelled due to shutdown signal');
    38→			return;
    39→		}
    40→
    41→		try {
    42→			this.redshiftTrendingItemsService.resetCancellation();
    43→
    44→			if (options.lastWeek) {
    45→				this.logger.log('Processing last week data for cron job');
    46→				this.currentOperation =
    47→					this.redshiftTrendingItemsService.fetchAndProcessLastWeekData();
    48→				await this.currentOperation;
    49→				this.logger.log('Successfully updated trending items with last week data');
    50→				return;
    51→			}
    52→
    53→			const currentYear = new Date().getFullYear();
    54→			const startYear = options.startYear ?? currentYear - 5;
    55→			const endYear = options.endYear ?? currentYear;
    56→
    57→			let monthsToProcess: number[] | undefined;
    58→			if (options.months) {
    59→				monthsToProcess = options.months.split(',').map((m) => parseInt(m.trim(), 10));
    60→				if (monthsToProcess.some((m) => isNaN(m) || m < 1 || m > 12)) {
    61→					throw new Error('Invalid month values. Months must be between 1 and 12.');
    62→				}
    63→			}
    64→
    65→			// eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
    66→			if (this.isShuttingDown) {
    67→				this.logger.warn('Command cancelled due to shutdown signal');
    68→				return;
    69→			}
    70→
    71→			this.logger.log(
