   146→	private setupGracefulShutdown(): void {
   147→		const signals: NodeJS.Signals[] = ['SIGTERM', 'SIGINT', 'SIGHUP', 'SIGQUIT'];
   148→
   149→		signals.forEach((signal) => {
   150→			process.on(signal, () => {
   151→				void this.handleShutdown(signal);
   152→			});
   153→		});
   154→
   155→		process.on('uncaughtException', (error) => {
   156→			this.logger.error(`Uncaught exception: ${error.message}`);
   157→			void this.handleShutdown('SIGTERM');
   158→		});
   159→
   160→		process.on('unhandledRejection', (reason) => {
   161→			this.logger.error(`Unhandled rejection: ${String(reason)}`);
   162→			void this.handleShutdown('SIGTERM');
   163→		});
   164→	}
   165→
   166→	private async handleShutdown(signal: string): Promise<void> {
   167→		if (this.isShuttingDown) {
   168→			this.logger.warn('Force shutdown requested, exiting immediately');
   169→			process.exit(1);
   170→		}
   171→
   172→		this.logger.warn(`Received ${signal} signal, initiating graceful shutdown...`);
   173→		this.isShuttingDown = true;
   174→
   175→		this.redshiftTrendingItemsService.cancelOperation();
   176→
   177→		try {
   178→			if (this.currentOperation) {
   179→				this.logger.log('Waiting for current operation to complete...');
   180→
   181→				const shutdownTimeout = setTimeout(() => {
   182→					this.logger.error('Graceful shutdown timeout, forcing exit');
   183→					process.exit(1);
   184→				}, 30000);
   185→
   186→				await this.currentOperation;
   187→				clearTimeout(shutdownTimeout);
   188→			}
   189→
   190→			this.logger.log('Graceful shutdown completed');
   191→			process.exit(0);
   192→		} catch (error) {
   193→			this.logger.error(`Error during shutdown: ${(error as Error).message}`);
   194→			process.exit(1);
   195→		}
   196→	}
   197→}
