    41→function generateDateRange(startDate: string, endDate: string, count: number): string[] {
    42→	const start = new Date(startDate);
    43→	const end = new Date(endDate);
    44→	const totalDays =
    45→		Math.floor((end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24)) + 1;
    46→	const step = totalDays / count;
    47→
    48→	const dates: string[] = [];
    49→	for (let i = 0; i < count; i++) {
    50→		const currentDate = new Date(start.getTime() + i * step * 24 * 60 * 60 * 1000);
    51→		const dateArr = currentDate.toISOString().split('T') as [string, string];
    52→		dates.push(dateArr[0]);
    53→	}
    54→	return dates;
    55→}
    56→
    57→function generateFutureDates(endDate: string, forecastDays: number): string[] {
    58→	const dates: string[] = [];
    59→	const startDate = new Date(endDate);
    60→
    61→	for (let i = 1; i <= forecastDays; i++) {
    62→		const futureDate = new Date(startDate);
    63→		futureDate.setDate(startDate.getDate() + i);
    64→		const dateArr = futureDate.toISOString().split('T') as [string, string];
    65→		dates.push(dateArr[0]);
    66→	}
    67→
    68→	return dates;
    69→}
