   280→function createComprehensiveForecast({
   281→	yearlyComponent,
   282→	monthlyComponent,
   283→	weeklyComponent,
   284→	quarterlyComponent,
   285→	trendComponent,
   286→	smoothedResidualsArr,
   287→	historicalLength,
   288→	forecastDays,
   289→	endDate,
   290→}: {
   291→	yearlyComponent: number[];
   292→	monthlyComponent: number[];
   293→	weeklyComponent: number[];
   294→	quarterlyComponent: number[];
   295→	trendComponent: number[];
   296→	smoothedResidualsArr: number[];
   297→	historicalLength: number;
   298→	forecastDays: number;
   299→	endDate: string;
   300→	purchasesArr: number[];
   301→}) {
   302→	const forecastDates = generateFutureDates(endDate, forecastDays);
   303→
   304→	const harmonics = getHarmonicsByObservationsCount({
   305→		observations: historicalLength,
   306→	});
   307→
   308→	const extendedYearly = extendSeasonalComponent(
   309→		yearlyComponent,
   310→		365,
   311→		harmonics,
   312→		historicalLength,
   313→		forecastDates,
   314→		endDate,
   315→	);
   316→	const extendedMonthly = extendSeasonalComponent(
   317→		monthlyComponent,
   318→		30,
   319→		harmonics,
   320→		historicalLength,
   321→		forecastDates,
   322→		endDate,
   323→	);
   324→	const extendedWeekly = extendSeasonalComponent(
   325→		weeklyComponent,
   326→		7,
   327→		harmonics,
   328→		historicalLength,
   329→		forecastDates,
   330→		endDate,
   331→	);
   332→	const extendedQuarterly = extendSeasonalComponent(
   333→		quarterlyComponent,
   334→		91,
   335→		harmonics,
   336→		historicalLength,
   337→		forecastDates,
   338→		endDate,
   339→	);
   340→
   341→	const extendedResiduals = extendResidualsComponent({
   342→		smoothedResidualsArr,
   343→		forecastDays,
   344→		endDate,
   345→	});
   346→
   347→	const extendedTrend = extendTrendComponent(trendComponent, forecastDays);
   348→
   349→	const forecastValues = Array(forecastDays)
   350→		.fill(0)
   351→		.map((_, i) => {
   352→			const yearly = extendedYearly[i] ?? 0;
   353→			const monthly = extendedMonthly[i] ?? 0;
   354→			const weekly = extendedWeekly[i] ?? 0;
   355→			const quarterly = extendedQuarterly[i] ?? 0;
   356→			const trend = extendedTrend[i] ?? 0;
   357→			const residual = extendedResiduals[i] ?? 0;
   358→			const forecastValue = trend + yearly + monthly + weekly + quarterly + residual;
   359→			return Math.max(0, forecastValue);
   360→		});
   361→
   362→	return {
   363→		forecastValues,
   364→		forecastDates,
   365→		components: {
   366→			yearly: extendedYearly,
   367→			monthly: extendedMonthly,
   368→			weekly: extendedWeekly,
   369→			quarterly: extendedQuarterly,
   370→			trend: extendedTrend,
   371→			residuals: extendedResiduals,
   372→		},
   373→	};
   374→}
