   117→		categoryNameToIdMap.set('Computer Accessories'.toLowerCase(), 210);
   118→		categoryNameToIdMap.set('Baseball & Softball Jerseys'.toLowerCase(), 151);
   119→		categoryNameToIdMap.set('Basketball Jerseys'.toLowerCase(), 153);
   120→		categoryNameToIdMap.set('Pens'.toLowerCase(), 49);
   121→		categoryNameToIdMap.set('Chargers & Adapters'.toLowerCase(), 215);
   122→		categoryNameToIdMap.set('Sports & Fitness'.toLowerCase(), 200);
   123→
   124→		categories.forEach((category) => {
   125→			const categoryName = String(category['name']);
   126→			categoryNameToIdMap.set(categoryName.toLowerCase(), category._id);
   127→		});
   128→
   129→		const processedCorrelations: {
   130→			primaryCategoryId: number;
   131→			edgeId: number;
   132→			edgeWeight: number;
   133→		}[] = [];
   134→		let matchedRecords = 0;
   135→		const badCategories = new Set();
   136→
   137→		for (const record of correlationData) {
   138→			const quoteSubCategoryId = categoryNameToIdMap.get(
   139→				record.quote_sub_category.toLowerCase(),
   140→			);
   141→			const selectProductSubCategoryId = categoryNameToIdMap.get(
   142→				record.select_product_sub_category.toLowerCase(),
   143→			);
   144→
   145→			if (
   146→				quoteSubCategoryId &&
   147→				selectProductSubCategoryId &&
   148→				quoteSubCategoryId !== selectProductSubCategoryId
   149→			) {
   150→				processedCorrelations.push({
   151→					primaryCategoryId: quoteSubCategoryId,
