   208→	private setupGracefulShutdown(): void {
   209→		const signals: NodeJS.Signals[] = ['SIGTERM', 'SIGINT', 'SIGHUP', 'SIGQUIT'];
   210→
   211→		signals.forEach((signal) => {
   212→			process.on(signal, () => {
   213→				void this.handleShutdown(signal);
   214→			});
   215→		});
   216→
   217→		process.on('uncaughtException', (error) => {
   218→			this.logger.error(`Uncaught exception: ${error.message}`);
   219→			void this.handleShutdown('SIGTERM');
   220→		});
   221→
   222→		process.on('unhandledRejection', (reason) => {
   223→			this.logger.error(`Unhandled rejection: ${String(reason)}`);
   224→			void this.handleShutdown('SIGTERM');
   225→		});
   226→	}
   227→
   228→	private async handleShutdown(signal: string): Promise<void> {
   229→		if (this.isShuttingDown) {
   230→			this.logger.warn('Force shutdown requested, exiting immediately');
   231→			process.exit(1);
   232→		}
   233→
   234→		this.logger.warn(`Received ${signal} signal, initiating graceful shutdown...`);
   235→		this.isShuttingDown = true;
   236→
   237→		try {
   238→			if (this.currentOperation) {
   239→				this.logger.log('Waiting for current operation to complete...');
   240→
   241→				const shutdownTimeout = setTimeout(() => {
   242→					this.logger.error('Graceful shutdown timeout, forcing exit');
   243→					process.exit(1);
   244→				}, 30000);
   245→
   246→				await this.currentOperation;
   247→				clearTimeout(shutdownTimeout);
   248→			}
   249→
   250→			this.logger.log('Graceful shutdown completed');
   251→			process.exit(0);
   252→		} catch (error) {
   253→			this.logger.error(`Error during shutdown: ${(error as Error).message}`);
   254→			process.exit(1);
   255→		}
   256→	}
   257→}
