   133→	private getParentCategoryIds(
   134→		categoryId: number,
   135→		categoryMap: Map<number, MMSAllStyleCategory>,
   136→	): number[] {
   137→		const parentIds: number[] = [];
   138→		let currentCategoryId: number | null = categoryId;
   139→
   140→		while (currentCategoryId) {
   141→			const category = categoryMap.get(currentCategoryId);
   142→			if (!category) {
   143→				break;
   144→			}
   145→
   146→			const parentId = category['parent_id'];
   147→			if (!parentId || parentId === this.ROOT_CAT_ID) {
