     1→export class ProgressBar {
     2→	private total: number;
     3→	private width: number;
     4→	private charComplete: string;
     5→	private charIncomplete: string;
     6→	private current = 0;
     7→	private lastDraw = '';
     8→
     9→	constructor(options?: {
    10→		total?: number;
    11→		width?: number;
    12→		charComplete?: string;
    13→		charIncomplete?: string;
    14→	}) {
    15→		this.total = options?.total ?? 0;
    16→		this.width = options?.width ?? 40;
    17→		this.charComplete = options?.charComplete ?? '=';
    18→		this.charIncomplete = options?.charIncomplete ?? '-';
    19→	}
    20→
    21→	update(current: number, metadata?: Record<string, string | number>): void {
    22→		this.current = current;
    23→
    24→		if (this.total !== 0) {
    25→			const percent = Math.min(this.current / this.total, 1);
    26→			const completeLength = Math.round(this.width * percent);
    27→			const incompleteLength = this.width - completeLength;
    28→
    29→			let bar =
    30→				`[${this.charComplete.repeat(completeLength)}${this.charIncomplete.repeat(incompleteLength)}]` +
    31→				` ${Math.round(percent * 100)}% (${this.current}/${this.total})`;
    32→
    33→			if (metadata?.['updatedCount'] !== undefined) {
    34→				bar += ` - Updated: ${metadata['updatedCount']}`;
    35→			}
    36→
    37→			this.draw(bar);
    38→
    39→			if (percent === 1) {
    40→				process.stdout.write('\n');
    41→			}
    42→		} else {
    43→			let bar =
    44→				`[${this.charComplete.repeat(this.current % (this.width + 1)).padEnd(this.width, this.charIncomplete)}]` +
    45→				` ${this.current}/?`;
    46→
    47→			if (metadata?.['updatedCount'] !== undefined) {
    48→				bar += ` - Updated: ${metadata['updatedCount']}`;
    49→			}
    50→
    51→			this.draw(bar);
    52→		}
    53→	}
    54→
    55→	increment(by = 1, metadata?: Record<string, string | number>): void {
    56→		this.update(this.current + by, metadata);
    57→	}
    58→
    59→	private draw(bar: string): void {
    60→		if (bar !== this.lastDraw) {
    61→			// eslint-disable-next-line
    62→			if (process.stdout.clearLine && process.stdout.cursorTo) {
    63→				process.stdout.clearLine(0);
    64→				process.stdout.cursorTo(0);
    65→				process.stdout.write(bar);
    66→			} else {
    67→				process.stdout.write(bar + '\n');
    68→			}
    69→			this.lastDraw = bar;
    70→		}
    71→	}
    72→
    73→	finish(): void {
    74→		if (this.total === 0) {
    75→			process.stdout.write('\n');
    76→		}
    77→	}
    78→}
