## 2. **Error Handling & Logging Patterns**

### A. CronJobExecution Decorator (Core Pattern)
**File:** `/src/decorators/cron-job-execution.decorator.ts`

```typescript
export function CronJobExecution(options: CronJobExecutionOptions): MethodDecorator {
  const { jobName, context = {} } = options;

  return function (
    target: unknown,
    _propertyKey: string | symbol,
    descriptor: PropertyDescriptor,
  ) {
    const originalMethod = descriptor.value as (...args: unknown[]) => unknown;
    const className = (target as { constructor: { name: string } }).constructor.name;
    const logger = new Logger(className);

    descriptor.value = async function (...args: unknown[]) {
      const startTime = performance.now();

      logger.log(`Starting ${jobName}`);
      rollbar.info(`Starting ${jobName}`, {
        command: jobName,
        ...context,
      });

      try {
        await originalMethod.apply(this, args);

        const executionTimeMs = performance.now() - startTime;

        logger.log(`${jobName} completed. Duration: ${formatDuration(executionTimeMs)}`);
        rollbar.info(`${jobName} completed`, {
          command: jobName,
          executionTimeMs,
          executionTimeFormatted: formatDuration(executionTimeMs),
          ...context,
        });

        rollbar.wait(() => {
          process.exit(0);
        });
      } catch (error) {
        const executionTimeMs = performance.now() - startTime;

        logger.error(
          `${jobName} failed after ${formatDuration(executionTimeMs)}:`,
          (error as Error).stack,
        );
        rollbar.error(`${jobName} failed`, {
          command: jobName,
          executionTimeMs,
          executionTimeFormatted: formatDuration(executionTimeMs),
          error: error instanceof Error ? error.message : String(error),
          ...context,
        });

        rollbar.wait(() => {
          process.exit(1);
        });
      }
    };

    return descriptor;
  };
}
```

**Features:**
- Automatic performance tracking with `performance.now()`
- Dual logging: NestJS Logger + Rollbar for monitoring
- Formatted duration output (e.g., "2h 35m 42s")
- Graceful exit codes (0 for success, 1 for failure)
- Context metadata capture for debugging

### B. Graceful Shutdown Pattern

**File:** `/src/modules/cli/commands/populate-trending-items.command.ts`

```typescript
export class PopulateTrendingItemsCommand extends CommandRunner {
  private isShuttingDown = false;
  private currentOperation: Promise<void> | null = null;

  constructor(private readonly redshiftTrendingItemsService: RedshiftTrendingItemsService) {
    super();
    this.setupGracefulShutdown();
  }

  private setupGracefulShutdown(): void {
    const signals: NodeJS.Signals[] = ['SIGTERM', 'SIGINT', 'SIGHUP', 'SIGQUIT'];

    signals.forEach((signal) => {
      process.on(signal, () => {
        void this.handleShutdown(signal);
      });
    });

    process.on('uncaughtException', (error) => {
      this.logger.error(`Uncaught exception: ${error.message}`);
      void this.handleShutdown('SIGTERM');
    });

    process.on('unhandledRejection', (reason) => {
      this.logger.error(`Unhandled rejection: ${String(reason)}`);
      void this.handleShutdown('SIGTERM');
    });
  }

  private async handleShutdown(signal: string): Promise<void> {
    if (this.isShuttingDown) {
      this.logger.warn('Force shutdown requested, exiting immediately');
      process.exit(1);
    }

    this.logger.warn(`Received ${signal} signal, initiating graceful shutdown...`);
    this.isShuttingDown = true;

    this.redshiftTrendingItemsService.cancelOperation();

    try {
      if (this.currentOperation) {
        this.logger.log('Waiting for current operation to complete...');

        const shutdownTimeout = setTimeout(() => {
          this.logger.error('Graceful shutdown timeout, forcing exit');
          process.exit(1);
        }, 30000);

        await this.currentOperation;
        clearTimeout(shutdownTimeout);
      }

      this.logger.log('Graceful shutdown completed');
      process.exit(0);
    } catch (error) {
      this.logger.error(`Error during shutdown: ${(error as Error).message}`);
      process.exit(1);
    }
  }
}
```

**Features:**
- Listens for system signals (SIGTERM, SIGINT, SIGHUP, SIGQUIT)
- Tracks uncaught exceptions and unhandled rejections
- 30-second timeout for graceful completion
- Forces exit if timeout exceeded

