**Features:**
- Uses Node.js `worker_threads` for CPU-intensive computation
- CPU count-based worker limit (max 8)
- 60-second timeout per worker
- `Promise.allSettled` for error isolation
- Development/production path resolution
- Incremental result saving to database

### B. Concurrency Pool Utility Pattern
**File:** `/src/utils/concurrency-pool.util.ts`

```typescript
export interface ConcurrencyPoolOptions<T, R> {
  items: T[];
  concurrency: number;
  handler: (item: T) => Promise<R>;
  onItemComplete?: (result: R, item: T) => void;
  onItemError?: (error: unknown, item: T) => void;
}

export async function runWithConcurrencyLimit<T, R>({
  items,
  concurrency,
  handler,
  onItemComplete,
  onItemError,
}: ConcurrencyPoolOptions<T, R>): Promise<ConcurrencyPoolResult<R>> {
  const results: R[] = [];
  const errors: { error: unknown; index: number }[] = [];
  let currentIndex = 0;

  async function processNext(): Promise<void> {
    while (currentIndex < items.length) {
      const index = currentIndex++;
      const item = items[index];

      if (item === undefined) {
        continue;
      }

      try {
        const result = await handler(item);
        results.push(result);
        onItemComplete?.(result, item);
      } catch (error) {
        errors.push({ error, index });
        onItemError?.(error, item);
      }
    }
  }

  const workers = Array.from({ length: Math.min(concurrency, items.length) }, () =>
    processNext(),
  );

  await Promise.all(workers);

  return { results, errors };
}
```

