## 4. **Progress Tracking**

**File:** `/src/utils/progress-bar.util.ts`

```typescript
export class ProgressBar {
  private total: number;
  private width: number;
  private charComplete: string;
  private charIncomplete: string;
  private current = 0;
  private lastDraw = '';

  constructor(options?: {
    total?: number;
    width?: number;
    charComplete?: string;
    charIncomplete?: string;
  }) {
    this.total = options?.total ?? 0;
    this.width = options?.width ?? 40;
    this.charComplete = options?.charComplete ?? '=';
    this.charIncomplete = options?.charIncomplete ?? '-';
  }

  update(current: number, metadata?: Record<string, string | number>): void {
    this.current = current;

    if (this.total !== 0) {
      const percent = Math.min(this.current / this.total, 1);
      const completeLength = Math.round(this.width * percent);
      const incompleteLength = this.width - completeLength;

      let bar =
        `[${this.charComplete.repeat(completeLength)}${this.charIncomplete.repeat(incompleteLength)}]` +
        ` ${Math.round(percent * 100)}% (${this.current}/${this.total})`;

      if (metadata?.['updatedCount'] !== undefined) {
        bar += ` - Updated: ${metadata['updatedCount']}`;
      }

      this.draw(bar);
    }
  }

  increment(by = 1, metadata?: Record<string, string | number>): void {
    this.update(this.current + by, metadata);
  }

  finish(): void {
    if (this.total === 0) {
      process.stdout.write('\n');
    }
  }
}
