}

private outputPromoSeedData(items: PromoSeedItem[]): void {
  const outputPath = path.join(process.cwd(), 'src', 'seeds', 'promo-seed-data.ts');

  let fileContent = '// Auto-generated by prepare-promo-seed command\n';
  fileContent += '// Generated on: ' + new Date().toISOString() + '\n\n';

  // Build TypeScript interface and data
  items.forEach((item) => {
    fileContent += '\t{\n';
    fileContent += `\t\tproduct_id: '${item.product_id}',\n`;
    fileContent += `\t\tproduct_name: '${item.product_name.replace(/'/g, "\\'")}',\n`;
    fileContent += `\t\tcategory_id: ${item.category_id},\n`;
    fileContent += `\t},\n`;
  });

  fs.writeFileSync(outputPath, fileContent, 'utf-8');
  this.logger.log(`Promo seed data written to: ${outputPath}`);
}
```

